@@ -0,0 +1,166 @@
+import { useEffect, useState } from "react";
+import { useParams, Link } from "react-router-dom";
+import axios from "axios";
+
+function Doctorid() {
+  const { id } = useParams(); // URL se product ID lega
+  const [product, setProduct] = useState(null);
+  const [loading, setLoading] = useState(true);
+  const [error, setError] = useState(null);
+
+  useEffect(() => {
+  axios.get(`http://localhost:3000/api/products/${id}`) // 👈 Backend se single product fetch
+      .then((res) => {
+        setProduct(res.data);
+        setLoading(false);
+      })
+      .catch((err) => {
+        console.log(err);
+        setError("Product nahi mila!");
+        setLoading(false);
+      });
+  }, [id]);
+
+  // Loading state
+  if (loading)
+    return <h2 style={{ textAlign: "center", marginTop: "50px" }}>Loading...</h2>;
+
+  // Error state
+  if (error)
+    return (
+      <div style={{ textAlign: "center", marginTop: "50px" }}>
+        <h2 style={{ color: "red" }}>{error}</h2>
+        <Link to="/" style={{ color: "blue" }}>
+          ← Home par wapas jao
+        </Link>
+      </div>
+    );
+
+  // Product nahi mila
+  if (!product)
+    return (
+      <div style={{ textAlign: "center", marginTop: "50px" }}>
+        <h2>Product nahi mila 😕</h2>
+        <Link to="/">← Home par wapas jao</Link>
+      </div>
+    );
+
+  return (
+    <div style={{ padding: "30px", maxWidth: "800px", margin: "0 auto" }}>
+      
+      {/* Back Button */}
+      <Link
+        to="/"
+        style={{
+          display: "inline-block",
+          marginBottom: "20px",
+          color: "#333",
+          textDecoration: "none",
+          fontSize: "16px",
+          fontWeight: "bold",
+        }}
+      >
+        ← Wapas Products List
+      </Link>
+
+      {/* Product Card */}
+      <div
+        style={{
+          border: "1px solid #ddd",
+          borderRadius: "12px",
+          padding: "30px",
+          backgroundColor: "#fff",
+          boxShadow: "0 4px 20px rgba(0,0,0,0.1)",
+        }}
+      >
+        {/* Product Image */}
+        {product.image && (
+          <img
+            src={product.image}
+            alt={product.name}
+            style={{
+              width: "100%",
+              height: "350px",
+              objectFit: "cover",
+              borderRadius: "10px",
+              marginBottom: "20px",
+            }}
+          />
+        )}
+
+        {/* Product Name */}
+        <h1 style={{ margin: "10px 0", fontSize: "28px", color: "#222" }}>
+          {product.name}
+        </h1>
+
+        {/* Product Price */}
+        {product.price && (
+          <p
+            style={{
+              fontWeight: "bold",
+              color: "#e44",
+              fontSize: "24px",
+              margin: "10px 0",
+            }}
+          >
+            💰 ₹{product.fee}
+          </p>
+        )}
+
+        {/* Product Description */}
+        {product.description && (
+          <p
+            style={{
+              color: "#666",
+              fontSize: "16px",
+              lineHeight: "1.7",
+              margin: "15px 0",
+            }}
+          >
+            {product.description}
+          </p>
+        )}
+
+        {/* Extra Fields - jo bhi MongoDB mein ho */}
+        {product.category && (
+          <p style={{ color: "#555", fontSize: "15px" }}>
+            📦 <strong>Category:</strong> {product.category}
+          </p>
+        )}
+
+        {product.stock !== undefined && (
+          <p style={{ color: "#555", fontSize: "15px" }}>
+            🏪 <strong>Stock:</strong>{" "}
+            <span style={{ color: product.stock > 0 ? "green" : "red" }}>
+              {product.stock > 0 ? `${product.stock} available` : "Out of Stock"}
+            </span>
+          </p>
+        )}
+
+        {/* Buy Button */}
+        <button
+          style={{
+            marginTop: "25px",
+            padding: "14px 35px",
+            backgroundColor: "#e44",
+            color: "#fff",
+            border: "none",
+            borderRadius: "8px",
+            fontSize: "18px",
+            cursor: "pointer",
+            fontWeight: "bold",
+            width: "100%",
+            transition: "background 0.2s",
+          }}
+          onMouseEnter={(e) => (e.target.style.backgroundColor = "#c33")}
+          onMouseLeave={(e) => (e.target.style.backgroundColor = "#e44")}
+          onClick={() => alert(`${product.name} cart mein add ho gaya! 🛒`)}
+        >
+          🛒 Cart Mein Dalo
+        </button>
+      </div>
+    </div>
+  );
+}
+
+export default Doctorid;
